/* mapper.member.com.erns.coching.MemberDAO.getList */ SELECT
FROM T_MEMB_INF AA INNER JOIN T_PARTNER_INF BB ON AA.PTN_SEQ = BB.PTN_SEQ
AND AA.WTDR_YN = 'N'

mapper.insert:
	/* mapper.member.com.erns.coching.MemberDAO.insert */


		SELECT
		nextval('seq_t_memb_inf') AS membSeq,
		gen_salt('md5') AS SALT;


    INSERT INTO T_MEMB_INF (
          MEMB_SEQ
        , MEMB_ID
        , MEMB_TYPE
        , PTN_SEQ
        , SALT
        , PSWD
        , MEMB_NAME
        , NICKNAME
        , PHONE
        , EMAIL
        , EMAIL_YN
        , MESSAGE_YN
        , JOIN_DTTM
        , USE_YN
        , WTDR_YN
        , WTDR_DTTM
        , DORMANT_YN
        , PSWD_CHNG_DTTM
        , PSWD_ERR_CNT
        , PSWD_INIT_YN
        , PSWD_EXP_DTTM
        , RCT_ACS_DTTM
        , RCT_ACS_IP
        , RGTR
        , RGT_DTTM
        , CHNR
        , CHNG_DTTM
    ) VALUES (
          #{membSeq, jdbcType=INTEGER}
        , #{membId, jdbcType=VARCHAR}
        , #{membType, jdbcType=VARCHAR}
        , #{ptnSeq, jdbcType=INTEGER}
        , #{salt, jdbcType=VARCHAR}
        , ENCODE(DIGEST(#{pswd, jdbcType=VARCHAR} || #{salt,jdbcType=VARCHAR}, 'sha512'), 'hex')
        , #{membName, jdbcType=VARCHAR}
        , #{nickname, jdbcType=VARCHAR}
        , #{phone, jdbcType=VARCHAR}
        , #{email, jdbcType=VARCHAR}
        , COALESCE(#{emailYn, jdbcType=CHAR}, 'N')
        , COALESCE(#{messageYn, jdbcType=CHAR}, 'N')
        , now()
        , COALESCE(NULLIF(#{useYn, jdbcType=CHAR}, ''), 'Y')
		, COALESCE(#{wtdrYn, jdbcType=CHAR}, 'N')
        , #{wtdrDttm, jdbcType=TIMESTAMP}
        , COALESCE(#{dormantYn, jdbcType=CHAR}, 'N')
        , now()
        , 0
        , COALESCE(#{pswdInitYn, jdbcType=CHAR}, 'N')
        , #{pswdExpDttm, jdbcType=TIMESTAMP}
        , #{rctAcsDttm, jdbcType=TIMESTAMP}
        , #{rctAcsIp, jdbcType=VARCHAR}
        , #{rgtr, jdbcType=INTEGER}
        , now()
        , #{chnr, jdbcType=INTEGER}
        , now()
	)

mapper.update:
/* mapper.member.com.erns.coching.MemberDAO.update */

UPDATE T_MEMB_INF SET
	MEMB_NAME = 		#{membName	, jdbcType=VARCHAR}
	, PHONE = 			#{phone		, jdbcType=VARCHAR}
	, EMAIL = 			#{email		, jdbcType=VARCHAR}
	, NICKNAME = 		#{nickname	, jdbcType=VARCHAR}
	, USE_YN = 			#{useYn		, jdbcType=VARCHAR}

	, CHNR = 			#{chnr		, jdbcType=INTEGER}
	, CHNG_DTTM = 		now()

	AND MEMB_SEQ = #{membSeq, jdbcType=INTEGER}
	AND PTN_SEQ = #{ptnSeq, jdbcType=INTEGER}

/* mapper.member.com.erns.coching.MemberDAO.updateAuth */

UPDATE T_MEMB_INF SET
USE_YN = 		#{useYn		, jdbcType=VARCHAR}
, CHNR = 		#{chnr	, jdbcType=INTEGER}
, CHNG_DTTM = 	now()

	AND MEMB_SEQ = #{membSeq, jdbcType=INTEGER}

mapper.delete:
/* com.nd.owner.member.mapper.MemberDAO.delete */

DELETE FROM T_MEMB_INF

	AND MEMB_SEQ = #{membSeq, jdbcType=INTEGER}

mapper.update:
/* mapper.member.com.erns.coching.MemberDAO.updateWithdrawYn */
UPDATE T_MEMB_INF SET
WTDR_YN 		= #{withdrawYn	, jdbcType=CHAR}
, WTDR_DTTM = CASE #{withdrawYn, jdbcType=VARCHAR} WHEN 'Y' THEN now() ELSE NULL END


	, MEMB_NAME		= NULL
	, NICKNAME		= NULL
	, PHONE			= NULL
	, EMAIL			= NULL

, CHNR 			= #{chnrSeq		, jdbcType=INTEGER}
, CHNG_DTTM 	= now()

	AND MEMB_SEQ = #{seq, jdbcType=INTEGER}

/* mapper.member.com.erns.coching.MemberDAO.updateDormantYn */

UPDATE T_MEMB_INF SET
      DORMANT_YN	= #{dormantYn	, jdbcType=CHAR}

	AND MEMB_SEQ = #{seq, jdbcType=INTEGER}

mapper.select:
/* mapper.member.com.erns.coching.MemberDAO.loadMembInfo */
SELECT PI.PTN_SEQ , PI.PTN_NAME , PI.PTN_LIC , PI.NATION , MI.MEMB_SEQ , MI.MEMB_ID , MI.MEMB_NAME , MI.NICKNAME , MI.EMAIL , MI.USE_YN , MI.PHONE FROM T_MEMB_INF MI JOIN T_PARTNER_INF PI ON MI.PTN_SEQ = PI.PTN_SEQ
AND MI.MEMB_SEQ = #{value , jdbcType=INTEGER}

/* mapper.member.com.erns.coching.MemberDAO.load */
SELECT AA.PSWD AS PSWD FROM T_MEMB_INF AA
AND AA.WTDR_YN = 'N'

mapper.update:
/* mapper.member.com.erns.coching.MemberDAO.update */


	SELECT gen_salt('md5') AS SALT;


UPDATE T_MEMB_INF SET
	PSWD = 				ENCODE(DIGEST(#{pswd, jdbcType=VARCHAR} || #{salt,jdbcType=VARCHAR}, 'sha512'), 'hex')
	, SALT =			#{salt		, jdbcType=VARCHAR}

	, PSWD_CHNG_DTTM =	now()	/* 비밀번호 변경일 */
	, PSWD_ERR_CNT =	0	/* 비밀번호 오류 횟수 */
	, PSWD_INIT_YN = 	#{pswdInitYn, jdbcType=VARCHAR}

	, CHNR = 			#{chnr		, jdbcType=INTEGER}
	, CHNG_DTTM = 		now()

	AND MEMB_SEQ = #{membSeq, jdbcType=INTEGER}

